 17→package org.apache.kafka.streams.processor.internals;
 18→
 19→import org.apache.kafka.common.TopicPartition;
 20→import org.apache.kafka.common.utils.LogContext;
 21→import org.apache.kafka.streams.processor.TaskId;
 22→import org.apache.kafka.streams.processor.internals.Task.State;
 23→
 24→import org.slf4j.Logger;
 25→
 26→import java.util.Collection;
 27→import java.util.Collections;
 28→import java.util.HashMap;
 29→import java.util.HashSet;
 30→import java.util.Iterator;
 31→import java.util.Map;
 32→import java.util.Set;
 33→import java.util.TreeMap;
 34→import java.util.stream.Collectors;
 35→
 36→import static org.apache.kafka.common.utils.Utils.filterMap;
 37→import static org.apache.kafka.common.utils.Utils.union;
 38→
 39→/**
 40→ * All tasks contained by the Streams instance.
 41→ *
 42→ * Note that these tasks are shared between the TaskManager (stream thread) and the StateUpdater (restore thread),
 43→ * i.e. all running active tasks are processed by the former and all restoring active tasks and standby tasks are
 44→ * processed by the latter.
 45→ */
 46→class Tasks implements TasksRegistry {
 47→    private final Logger log;
 48→
 49→    // note that these two maps may be accessed by concurrent threads and hence
 50→    // should be synchronized when accessed
 51→    private final Map<TaskId, StreamTask> activeTasksPerId = new TreeMap<>();
 52→    private final Map<TaskId, StandbyTask> standbyTasksPerId = new TreeMap<>();
 53→
 54→    // Tasks may have been assigned for a NamedTopology that is not yet known by this host. When that occurs we stash
 55→    // these unknown tasks until either the corresponding NamedTopology is added and we can create them at last, or
 56→    // we receive a new assignment and they are revoked from the thread.
 57→    private final Map<TaskId, Set<TopicPartition>> pendingActiveTasksToCreate = new HashMap<>();
 58→    private final Map<TaskId, Set<TopicPartition>> pendingStandbyTasksToCreate = new HashMap<>();
 59→    private final Set<Task> pendingTasksToInit = new HashSet<>();
 60→    private final Set<Task> pendingTasksToClose = new HashSet<>();
 61→    private final Set<TaskId> failedTaskIds = new HashSet<>();
 62→
 63→    private final Map<TopicPartition, StreamTask> activeTasksPerPartition = new HashMap<>();
 64→
 65→    Tasks(final LogContext logContext) {
 66→        this.log = logContext.logger(getClass());
 67→    }
 68→
 69→    @Override
 70→    public void clearPendingTasksToCreate() {
 71→        pendingActiveTasksToCreate.clear();
 72→        pendingStandbyTasksToCreate.clear();
 73→    }
 74→
 75→    @Override
 76→    public Map<TaskId, Set<TopicPartition>> drainPendingActiveTasksForTopologies(final Set<String> currentTopologies) {
 77→        final Map<TaskId, Set<TopicPartition>> pendingActiveTasksForTopologies =
 78→            filterMap(pendingActiveTasksToCreate, t -> currentTopologies.contains(t.getKey().topologyName()));
 79→
 80→        pendingActiveTasksToCreate.keySet().removeAll(pendingActiveTasksForTopologies.keySet());
 81→
 82→        return pendingActiveTasksForTopologies;
 83→    }
 84→
 85→    @Override
 86→    public Map<TaskId, Set<TopicPartition>> drainPendingStandbyTasksForTopologies(final Set<String> currentTopologies) {
 87→        final Map<TaskId, Set<TopicPartition>> pendingActiveTasksForTopologies =
 88→            filterMap(pendingStandbyTasksToCreate, t -> currentTopologies.contains(t.getKey().topologyName()));
 89→
 90→        pendingStandbyTasksToCreate.keySet().removeAll(pendingActiveTasksForTopologies.keySet());
 91→
 92→        return pendingActiveTasksForTopologies;
 93→    }
 94→
 95→    @Override
 96→    public void addPendingActiveTasksToCreate(final Map<TaskId, Set<TopicPartition>> pendingTasks) {
 97→        pendingActiveTasksToCreate.putAll(pendingTasks);
 98→    }
 99→
100→    @Override
101→    public void addPendingStandbyTasksToCreate(final Map<TaskId, Set<TopicPartition>> pendingTasks) {
102→        pendingStandbyTasksToCreate.putAll(pendingTasks);
103→    }
104→
105→    @Override
106→    public Set<Task> drainPendingTasksToInit() {
107→        final Set<Task> result = new HashSet<>(pendingTasksToInit);
108→        pendingTasksToInit.clear();
109→        return result;
110→    }
111→
112→    @Override
113→    public Set<StreamTask> drainPendingActiveTasksToInit() {
114→        final Set<StreamTask> result = new HashSet<>();
115→        final Iterator<Task> iterator = pendingTasksToInit.iterator();
116→        while (iterator.hasNext()) {
117→            final Task task = iterator.next();
118→            if (task.isActive()) {
119→                result.add((StreamTask) task);
120→                iterator.remove();
121→            }
122→        }
123→        return result;
124→    }
125→
126→    @Override
127→    public Set<StandbyTask> drainPendingStandbyTasksToInit() {
128→        final Set<StandbyTask> result = new HashSet<>();
129→        final Iterator<Task> iterator = pendingTasksToInit.iterator();
130→        while (iterator.hasNext()) {
131→            final Task task = iterator.next();
132→            if (!task.isActive()) {
133→                result.add((StandbyTask) task);
134→                iterator.remove();
135→            }
136→        }
137→        return result;
138→    }
139→
140→    @Override
141→    public Set<Task> pendingTasksToInit() {
142→        return Collections.unmodifiableSet(pendingTasksToInit);
143→    }
144→
145→    @Override
146→    public void addPendingTasksToInit(final Collection<? extends Task> tasks) {
147→        pendingTasksToInit.addAll(tasks);
148→    }
149→
150→    @Override
151→    public boolean hasPendingTasksToInit() {
152→        return !pendingTasksToInit.isEmpty();
153→    }
154→
155→    @Override
156→    public Set<Task> pendingTasksToClose() {
157→        return Collections.unmodifiableSet(pendingTasksToClose);
158→    }
159→
160→    @Override
161→    public void addPendingTasksToClose(final Collection<? extends Task> tasks) {
162→        pendingTasksToClose.addAll(tasks);
163→    }
164→
165→    @Override
166→    public boolean hasPendingTasksToClose() {
167→        return !pendingTasksToClose.isEmpty();
168→    }
169→
170→    @Override
171→    public void addActiveTasks(final Collection<StreamTask> newTasks) {
172→        if (!newTasks.isEmpty()) {
173→            for (final StreamTask activeTask : newTasks) {
174→                addActiveTask(activeTask);
175→            }
176→        }
177→    }
178→
179→    @Override
180→    public void addStandbyTasks(final Collection<StandbyTask> newTasks) {
181→        if (!newTasks.isEmpty()) {
182→            for (final StandbyTask standbyTask : newTasks) {
183→                addStandbyTask(standbyTask);
184→            }
185→        }
186→    }
187→
188→    @Override
189→    public void addTask(final Task task) {
190→        if (task.isActive()) {
191→            addActiveTask((StreamTask) task);
192→        } else {
193→            addStandbyTask((StandbyTask) task);
194→        }
195→    }
196→
197→    @Override
198→    public synchronized void addActiveTask(final StreamTask task) {
199→        final TaskId taskId = task.id();
200→
201→        if (activeTasksPerId.containsKey(taskId)) {
202→            throw new IllegalStateException("Attempted to create an active task that we already own: " + taskId);
203→        }
204→
205→        if (standbyTasksPerId.containsKey(taskId)) {
206→            throw new IllegalStateException("Attempted to create an active task while we already own its standby: " + taskId);
207→        }
208→
209→        activeTasksPerId.put(taskId, task);
210→        pendingActiveTasksToCreate.remove(taskId);
211→        for (final TopicPartition topicPartition : task.inputPartitions()) {
212→            activeTasksPerPartition.put(topicPartition, task);
213→        }
214→    }
215→
216→    @Override
217→    public synchronized void addStandbyTask(final StandbyTask task) {
218→        final TaskId taskId = task.id();
219→
220→        if (standbyTasksPerId.containsKey(taskId)) {
221→            throw new IllegalStateException("Attempted to create an standby task that we already own: " + taskId);
222→        }
223→
224→        if (activeTasksPerId.containsKey(taskId)) {
225→            throw new IllegalStateException("Attempted to create an standby task while we already own its active: " + taskId);
226→        }
227→
228→        standbyTasksPerId.put(taskId, task);
229→    }
230→
231→    @Override
232→    public void addFailedTask(final Task task) {
233→        failedTaskIds.add(task.id());
234→        addTask(task);
235→    }
236→
237→    @Override
238→    public synchronized void removeTask(final Task taskToRemove) {
239→        final TaskId taskId = taskToRemove.id();
240→
241→        if (taskToRemove.state() != Task.State.CLOSED && taskToRemove.state() != State.SUSPENDED) {
242→            throw new IllegalStateException("Attempted to remove a task that is not closed or suspended: " + taskId);
243→        }
244→
245→        if (pendingTasksToClose.contains(taskToRemove)) {
246→            pendingTasksToClose.remove(taskToRemove);
247→        } else if (taskToRemove.isActive()) {
248→            if (activeTasksPerId.remove(taskId) == null) {
249→                throw new IllegalArgumentException("Attempted to remove an active task that is not owned: " + taskId);
250→            }
251→            removePartitionsForActiveTask(taskId);
252→        } else {
253→            if (standbyTasksPerId.remove(taskId) == null) {
254→                throw new IllegalArgumentException("Attempted to remove a standby task that is not owned: " + taskId);
255→            }
256→        }
257→        failedTaskIds.remove(taskId);
258→    }
259→
260→    @Override
261→    public synchronized void replaceStandbyWithActive(final StreamTask activeTask) {
262→        final TaskId taskId = activeTask.id();
263→        if (standbyTasksPerId.remove(taskId) == null) {
264→            throw new IllegalStateException("Attempted to convert unknown standby task to stream task: " + taskId);
265→        }
266→
267→        activeTasksPerId.put(activeTask.id(), activeTask);
268→        for (final TopicPartition topicPartition : activeTask.inputPartitions()) {
269→            activeTasksPerPartition.put(topicPartition, activeTask);
270→        }
271→    }
272→
273→    @Override
274→    public boolean updateActiveTaskInputPartitions(final StreamTask task, final Set<TopicPartition> topicPartitions) {
275→        final boolean requiresUpdate = !task.inputPartitions().equals(topicPartitions);
276→        if (requiresUpdate) {
277→            log.debug("Update task {} inputPartitions: current {}, new {}", task, task.inputPartitions(), topicPartitions);
278→            for (final TopicPartition inputPartition : task.inputPartitions()) {
279→                activeTasksPerPartition.remove(inputPartition);
280→            }
281→            for (final TopicPartition topicPartition : topicPartitions) {
282→                activeTasksPerPartition.put(topicPartition, task);
283→            }
284→        }
285→
286→        return requiresUpdate;
287→    }
288→
289→    private void removePartitionsForActiveTask(final TaskId taskId) {
290→        final Set<TopicPartition> toBeRemoved = activeTasksPerPartition.entrySet().stream()
291→            .filter(e -> e.getValue().id().equals(taskId))
292→            .map(Map.Entry::getKey)
293→            .collect(Collectors.toSet());
294→        toBeRemoved.forEach(activeTasksPerPartition::remove);
295→    }
296→
297→    @Override
298→    public synchronized void clear() {
299→        pendingTasksToInit.clear();
300→        pendingTasksToClose.clear();
301→        pendingActiveTasksToCreate.clear();
302→        pendingStandbyTasksToCreate.clear();
303→        activeTasksPerId.clear();
304→        standbyTasksPerId.clear();
305→        activeTasksPerPartition.clear();
306→        failedTaskIds.clear();
307→    }
308→
309→    @Override
310→    public StreamTask activeInitializedTasksForInputPartition(final TopicPartition partition) {
311→        return activeTasksPerPartition.get(partition);
312→    }
313→
314→    private synchronized Task getTask(final TaskId taskId) {
315→        if (activeTasksPerId.containsKey(taskId)) {
316→            return activeTasksPerId.get(taskId);
317→        }
318→        if (standbyTasksPerId.containsKey(taskId)) {
319→            return standbyTasksPerId.get(taskId);
320→        }
321→        return null;
322→    }
323→
324→    @Override
325→    public Task initializedTask(final TaskId taskId) {
326→        final Task task = getTask(taskId);
327→
328→        if (task != null)
329→            return task;
330→        else
331→            throw new IllegalStateException("Task unknown: " + taskId);
332→    }
333→
334→    @Override
335→    public Collection<Task> initializedTasks(final Collection<TaskId> taskIds) {
336→        final Set<Task> tasks = new HashSet<>();
337→        for (final TaskId taskId : taskIds) {
338→            tasks.add(initializedTask(taskId));
339→        }
340→        return tasks;
341→    }
342→
343→    @Override
344→    public synchronized Collection<TaskId> activeInitializedTaskIds() {
345→        return Collections.unmodifiableCollection(activeTasksPerId.keySet());
346→    }
347→
348→    @Override
349→    public synchronized Collection<StreamTask> activeInitializedTasks() {
350→        return Collections.unmodifiableCollection(activeTasksPerId.values());
351→    }
352→
353→    @Override
354→    public synchronized Collection<StandbyTask> standbyInitializedTasks() {
355→        return Collections.unmodifiableCollection(standbyTasksPerId.values());
356→    }
357→
358→    /**
359→     * All tasks returned by any of the getters are read-only and should NOT be modified;
360→     * and the returned task could be modified by other threads concurrently
361→     */
362→    @Override
363→    public synchronized Set<Task> allInitializedTasks() {
364→        return union(HashSet::new, new HashSet<>(activeTasksPerId.values()), new HashSet<>(standbyTasksPerId.values()));
365→    }
366→
367→    @Override
368→    public synchronized Set<Task> allNonFailedInitializedTasks() {
369→        final Set<Task> nonFailedActiveTasks = activeTasksPerId.values().stream()
370→            .filter(task -> !failedTaskIds.contains(task.id()))
371→            .collect(Collectors.toSet());
372→        final Set<Task> nonFailedStandbyTasks = standbyTasksPerId.values().stream()
373→            .filter(task -> !failedTaskIds.contains(task.id()))
374→            .collect(Collectors.toSet());
375→        return union(HashSet::new, nonFailedActiveTasks, nonFailedStandbyTasks);
376→    }
377→
378→    @Override
379→    public synchronized Set<TaskId> allInitializedTaskIds() {
380→        return union(HashSet::new, activeTasksPerId.keySet(), standbyTasksPerId.keySet());
381→    }
382→
383→    @Override
384→    public synchronized Map<TaskId, Task> allInitializedTasksPerId() {
385→        final Map<TaskId, Task> ret = new HashMap<>();
386→        ret.putAll(activeTasksPerId);
387→        ret.putAll(standbyTasksPerId);
388→        return ret;
389→    }
390→
391→    @Override
392→    public boolean containsInitialized(final TaskId taskId) {
393→        return getTask(taskId) != null;
394→    }
395→
396→    Map<TaskId, Set<TopicPartition>> pendingActiveTasksToCreate() {
397→        return pendingActiveTasksToCreate;
398→    }
399→
400→    Map<TaskId, Set<TopicPartition>> pendingStandbyTasksToCreate() {
401→        return pendingStandbyTasksToCreate;
402→    }
403→}
