179→            if (!offsetsPerTask.isEmpty() || taskManager.streamsProducer().transactionInFlight()) {
180→                final Map<TopicPartition, OffsetAndMetadata> allOffsets = offsetsPerTask.values().stream()
181→                    .flatMap(e -> e.entrySet().stream()).collect(Collectors.toMap(Map.Entry::getKey, Map.Entry::getValue));
182→
183→                try {
184→                    taskManager.streamsProducer().commitTransaction(allOffsets, taskManager.consumerGroupMetadata());
185→                    updateTaskCommitMetadata(allOffsets);
186→                } catch (final TimeoutException timeoutException) {
187→                    log.error(
188→                        String.format("Committing task(s) %s failed.",
189→                                      offsetsPerTask
190→                                          .keySet()
191→                                          .stream()
192→                                          .map(t -> t.id().toString())
193→                                          .collect(Collectors.joining(", "))),
194→                        timeoutException
195→                    );
196→                    offsetsPerTask
197→                        .keySet()
198→                        .forEach(task -> corruptedTasks.add(task.id()));
199→                }
200→            }
201→        } else {
202→            // processingMode == ALOS
203→            if (!offsetsPerTask.isEmpty()) {
204→                final Map<TopicPartition, OffsetAndMetadata> allOffsets = offsetsPerTask.values().stream()
205→                    .flatMap(e -> e.entrySet().stream()).collect(Collectors.toMap(Map.Entry::getKey, Map.Entry::getValue));
206→
207→                try {
208→                    taskManager.consumerCommitSync(allOffsets);
209→                    updateTaskCommitMetadata(allOffsets);
210→                } catch (final CommitFailedException error) {
211→                    throw new TaskMigratedException("Consumer committing offsets failed, " +
212→                                                        "indicating the corresponding thread is no longer part of the group", error);
213→                } catch (final TimeoutException timeoutException) {
214→                    log.error(
215→                        String.format("Committing task(s) %s failed.",
216→                                      offsetsPerTask
217→                                          .keySet()
218→                                          .stream()
219→                                          .map(t -> t.id().toString())
220→                                          .collect(Collectors.joining(", "))),
221→                        timeoutException
222→                    );
223→                    throw timeoutException;
224→                } catch (final KafkaException error) {
225→                    throw new StreamsException("Error encountered committing offsets via consumer", error);
226→                }
227→            }
228→        }
229→        if (!corruptedTasks.isEmpty()) {
230→            throw new TaskCorruptedException(corruptedTasks);
231→        }
232→    }
233→
234→    private void updateTaskCommitMetadata(final Map<TopicPartition, OffsetAndMetadata> allOffsets) {
235→        if (!allOffsets.isEmpty()) {
236→            for (final StreamTask task : tasks.activeInitializedTasks()) {
237→                for (final TopicPartition topicPartition : task.inputPartitions()) {
238→                    if (allOffsets.containsKey(topicPartition)) {
239→                        task.updateCommittedOffsets(topicPartition, allOffsets.get(topicPartition).offset());
240→                    }
241→                }
242→            }
243→        }
244→    }
245→
246→    private void commitSuccessfullyProcessedTasks() {
247→        if (!executionMetadata.successfullyProcessed().isEmpty()) {
248→            log.info("Streams encountered an error when processing tasks." +
249→                " Will commit all previously successfully processed tasks {}",
250→                executionMetadata.successfullyProcessed().stream().map(Task::id));
251→            commitTasksAndMaybeUpdateCommittableOffsets(executionMetadata.successfullyProcessed(), new HashMap<>());
252→        }
253→        executionMetadata.clearSuccessfullyProcessed();
254→    }
255→
256→    /**
257→     * @throws TaskMigratedException if the task producer got fenced (EOS only)
258→     */
259→    int punctuate() {
260→        int punctuated = 0;
261→
262→        for (final StreamTask task : tasks.activeInitializedTasks()) {
263→            try {
264→                if (executionMetadata.canPunctuateTask(task)) {
265→                    if (task.maybePunctuateStreamTime()) {
266→                        punctuated++;
267→                    }
268→                    if (task.maybePunctuateSystemTime()) {
269→                        punctuated++;
270→                    }
271→                }
272→            } catch (final TaskMigratedException e) {
273→                log.info("Failed to punctuate stream task {} since it got migrated to another thread already. " +
274→                    "Will trigger a new rebalance and close all tasks as zombies together.", task.id());
275→                throw e;
276→            } catch (final StreamsException e) {
277→                log.error("Failed to punctuate stream task {} due to the following error:", task.id(), e);
278→                e.setTaskId(task.id());
279→                throw e;
280→            } catch (final KafkaException e) {
281→                log.error("Failed to punctuate stream task {} due to the following error:", task.id(), e);
282→                throw new StreamsException(e, task.id());
283→            }
284→        }
285→
286→        return punctuated;
287→    }
288→}
