 18→
 19→import org.apache.kafka.common.metrics.Sensor;
 20→import org.apache.kafka.common.utils.Bytes;
 21→import org.apache.kafka.streams.KeyValue;
 22→import org.apache.kafka.streams.processor.internals.metrics.StreamsMetricsImpl;
 23→import org.apache.kafka.streams.processor.internals.metrics.TaskMetrics;
 24→import org.apache.kafka.streams.state.internals.metrics.NamedCacheMetrics;
 25→
 26→import org.slf4j.Logger;
 27→import org.slf4j.LoggerFactory;
 28→
 29→import java.util.ArrayList;
 30→import java.util.Collections;
 31→import java.util.Iterator;
 32→import java.util.LinkedHashSet;
 33→import java.util.List;
 34→import java.util.NavigableMap;
 35→import java.util.Set;
 36→import java.util.TreeMap;
 37→import java.util.TreeSet;
 38→
 39→class NamedCache {
 40→    private static final Logger log = LoggerFactory.getLogger(NamedCache.class);
 41→    private final String name;
 42→    private final String storeName;
 43→    private final String taskName;
 44→    private final NavigableMap<Bytes, LRUNode> cache = new TreeMap<>();
 45→    private final Set<Bytes> dirtyKeys = new LinkedHashSet<>();
 46→    private ThreadCache.DirtyEntryFlushListener listener;
 47→    private LRUNode tail;
 48→    private LRUNode head;
 49→    private long currentSizeBytes;
 50→
 51→    private final StreamsMetricsImpl streamsMetrics;
 52→    private final Sensor hitRatioSensor;
 53→    private final Sensor totalCacheSizeSensor;
 54→
 55→    // internal stats
 56→    private long numReadHits = 0;
 57→    private long numReadMisses = 0;
 58→    private long numOverwrites = 0;
 59→    private long numFlushes = 0;
 60→
 61→    NamedCache(final String name, final StreamsMetricsImpl streamsMetrics) {
 62→        this.name = name;
 63→        this.streamsMetrics = streamsMetrics;
 64→        storeName = ThreadCache.underlyingStoreNamefromCacheName(name);
 65→        taskName = ThreadCache.taskIDfromCacheName(name);
 66→        hitRatioSensor = NamedCacheMetrics.hitRatioSensor(
 67→            streamsMetrics,
 68→            Thread.currentThread().getName(),
 69→            taskName,
 70→            storeName
 71→        );
 72→        totalCacheSizeSensor = TaskMetrics.totalCacheSizeBytesSensor(
 73→                Thread.currentThread().getName(),
 74→                taskName,
 75→                streamsMetrics
 76→        );
 77→    }
 78→
 79→    final synchronized String name() {
 80→        return name;
 81→    }
 82→
 83→    synchronized long hits() {
 84→        return numReadHits;
 85→    }
 86→
 87→    synchronized long misses() {
 88→        return numReadMisses;
 89→    }
 90→
 91→    synchronized long overwrites() {
 92→        return numOverwrites;
 93→    }
 94→
 95→    synchronized long flushes() {
 96→        return numFlushes;
 97→    }
 98→
 99→    synchronized LRUCacheEntry get(final Bytes key) {
100→        if (key == null) {
101→            return null;
102→        }
103→
104→        final LRUNode node = getInternal(key);
105→        if (node == null) {
106→            return null;
107→        }
108→        updateLRU(node);
109→        return node.entry;
110→    }
111→
112→    synchronized void setListener(final ThreadCache.DirtyEntryFlushListener listener) {
113→        this.listener = listener;
114→    }
115→
116→    synchronized void flush() {
117→        flush(null);
118→    }
119→
120→    private void flush(final LRUNode evicted) {
121→        numFlushes++;
122→
123→        if (log.isTraceEnabled()) {
124→            log.trace("Named cache {} stats on flush: #hits={}, #misses={}, #overwrites={}, #flushes={}",
125→                name, hits(), misses(), overwrites(), flushes());
126→        }
127→
128→        if (listener == null) {
129→            throw new IllegalArgumentException("No listener for namespace " + name + " registered with cache");
130→        }
131→
132→        if (dirtyKeys.isEmpty()) {
133→            return;
134→        }
135→
136→        final List<ThreadCache.DirtyEntry> entries = new ArrayList<>();
137→        final List<Bytes> deleted = new ArrayList<>();
138→
139→        // evicted already been removed from the cache so add it to the list of
140→        // flushed entries and remove from dirtyKeys.
141→        if (evicted != null) {
142→            entries.add(new ThreadCache.DirtyEntry(evicted.key, evicted.entry.value(), evicted.entry));
143→            dirtyKeys.remove(evicted.key);
144→        }
145→
146→        for (final Bytes key : dirtyKeys) {
147→            final LRUNode node = getInternal(key);
148→            if (node == null) {
149→                throw new IllegalStateException("Key = " + key + " found in dirty key set, but entry is null");
150→            }

